async (params, browser) => {
  // Open article page
  await browser.open(`${params.article_url}`)

  // Wait for article to load
  await browser.waitForSelector('article, h1, [role=\'main\'], .article-body, .story-body', 15000)

  // Let article render
  await browser.wait(2500)

  // Scroll to load full article
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract article details
  const article_data = await browser.evaluate(`const titleEl = document.querySelector('h1, [data-testid="headline"], .article-title, .headline, .entry-title, .post-title'); const authorEl = document.querySelector('[rel="author"], .author-name, .byline, [data-testid="byline"], .article-author, meta[name="author"]'); let author = ''; if (authorEl) { author = authorEl.getAttribute('content') || authorEl.textContent.trim(); } const dateEl = document.querySelector('time, [data-testid="published-timestamp"], .publish-date, .article-date, .entry-date, meta[property="article:published_time"]'); let date = ''; if (dateEl) { date = dateEl.getAttribute('datetime') || dateEl.getAttribute('content') || dateEl.textContent.trim(); } const sourceEl = document.querySelector('meta[property="og:site_name"]'); const source = sourceEl ? sourceEl.getAttribute('content') : window.location.hostname.replace('www.', ''); const contentParagraphs = []; const articleBody = document.querySelector('article, [role="main"], .article-body, .story-body, .entry-content, .post-content, .article-content'); const container = articleBody || document.body; const paragraphs = container.querySelectorAll('p'); for (let i = 0; i < paragraphs.length; i++) { const text = paragraphs[i].textContent.trim(); if (text.length > 30 && !text.includes('cookie') && !text.includes('subscribe') && !text.includes('sign up') && !text.includes('advertisement')) { contentParagraphs.push(text); } } const descMeta = document.querySelector('meta[property="og:description"], meta[name="description"]'); const description = descMeta ? descMeta.getAttribute('content') : ''; return { title: titleEl ? titleEl.textContent.trim() : '', author: author, date: date, source: source, description: description, content: contentParagraphs.slice(0, 20).join('\n\n').slice(0, 5000), paragraph_count: contentParagraphs.length, article_url: window.location.href }`)

  return article_data
}
